INSERT INTO `legal_documents` VALUES (1,'Terms & Conditions','Privacy Policy\n\nCryptoPulse (\"we\", \"our\", \"us\") is committed to protecting your personal data in accordance with applicable data protection laws.\n\n1. Data Collection\nWe may collect personal information including identity data, contact details, transaction records, device data, and verification documents.\n\n2. Purpose of Processing\nWe process data to:\n- Provide and manage services\n- Ensure platform security\n- Comply with legal obligations\n- Prevent fraud and abuse\n\n3. Legal Basis\nData processing is based on user consent, contractual necessity, and legal compliance.\n\n4. Data Sharing\nWe may share data with:\n- Payment processors\n- Verification providers\n- Regulatory authorities when required\n\n5. Data Security\nWe implement appropriate technical and organizational measures to safeguard user data.\n\n6. User Rights\nUsers may request access, correction, or deletion of personal data, subject to applicable laws.\n\n7. Data Retention\nData is retained only as long as necessary for operational and legal purposes.\n\n8. Updates\nWe may update this policy periodically.\n\n9. Contact\nFor privacy inquiries, contact support.',NULL,NULL,NULL,'2026-03-28 12:49:42','active','2026-03-27 21:46:08',NULL,'general'),(2,'Privacy Policy','Privacy Policy\r\n\r\nCryptoPulse (\"we\", \"our\", \"us\") is committed to protecting your personal data in accordance with applicable data protection laws.\r\n\r\n1. Data Collection\r\nWe may collect personal information including identity data, contact details, transaction records, device data, and verification documents.\r\n\r\n2. Purpose of Processing\r\nWe process data to:\r\n- Provide and manage services\r\n- Ensure platform security\r\n- Comply with legal obligations\r\n- Prevent fraud and abuse\r\n\r\n3. Legal Basis\r\nData processing is based on user consent, contractual necessity, and legal compliance.\r\n\r\n4. Data Sharing\r\nWe may share data with:\r\n- Payment processors\r\n- Verification providers\r\n- Regulatory authorities when required\r\n\r\n5. Data Security\r\nWe implement appropriate technical and organizational measures to safeguard user data.\r\n\r\n6. User Rights\r\nUsers may request access, correction, or deletion of personal data, subject to applicable laws.\r\n\r\n7. Data Retention\r\nData is retained only as long as necessary for operational and legal purposes.\r\n\r\n8. Updates\r\nWe may update this policy periodically.\r\n\r\n9. Contact\r\nFor privacy inquiries, contact support.',NULL,NULL,NULL,'2026-04-04 14:19:00','active','2026-03-27 21:46:08',NULL,'general'),(3,'Risk Disclosure','Risk Disclosure\n\nThe use of CryptoPulse involves significant risk. By using this Platform, you acknowledge and accept the following:\n\n1. No Financial Advice\nCryptoPulse does not provide investment, financial, or trading advice.\n\n2. High Risk Activity\nTrading-related activities carry a high level of risk and may result in significant losses.\n\n3. No Guarantee of Profit\nCryptoPulse does not guarantee profits or successful outcomes.\n\n4. System Limitations\nTechnical issues, delays, or interruptions may occur.\n\n5. User Responsibility\nUsers are solely responsible for their decisions and actions on the Platform.\n\n6. Acceptance of Risk\nBy using CryptoPulse, you confirm that you fully understand and accept all risks involved.\n\nIf you do not understand these risks, you should not use the Platform.',NULL,NULL,NULL,'2026-03-28 12:49:26','active','2026-03-27 21:46:08',NULL,'general'),(4,'Risk Disclosure','Risk Disclosure\n\nThe use of CryptoPulse involves significant risk. By using this Platform, you acknowledge and accept the following:\n\n1. No Financial Advice\nCryptoPulse does not provide investment, financial, or trading advice.\n\n2. High Risk Activity\nTrading-related activities carry a high level of risk and may result in significant losses.\n\n3. No Guarantee of Profit\nCryptoPulse does not guarantee profits or successful outcomes.\n\n4. System Limitations\nTechnical issues, delays, or interruptions may occur.\n\n5. User Responsibility\nUsers are solely responsible for their decisions and actions on the Platform.\n\n6. Acceptance of Risk\nBy using CryptoPulse, you confirm that you fully understand and accept all risks involved.\n\nIf you do not understand these risks, you should not use the Platform.',NULL,NULL,NULL,'2026-03-28 12:50:22','active','2026-03-28 12:50:15',NULL,'general'),(5,'KYC / AML Policy','KYC / AML Policy\n\nCryptoPulse implements Know Your Customer (KYC) and Anti-Money Laundering (AML) procedures in compliance with applicable regulations.\n\n1. Identity Verification\nUsers may be required to submit valid identification documents and verification data.\n\n2. Monitoring\nWe monitor transactions to detect suspicious activity.\n\n3. Compliance\nCryptoPulse reserves the right to:\n- Request additional verification\n- Restrict or suspend accounts\n- Report suspicious activities to authorities\n\n4. Prohibited Use\nThe Platform must not be used for money laundering, fraud, or illegal activities.\n\n5. Data Protection\nAll KYC data is securely stored and handled in accordance with privacy laws.',NULL,NULL,NULL,'2026-03-28 12:50:52','active','2026-03-28 12:50:52',NULL,'general'),(6,'? 5. Refund Policy','Refund & Cancellation Policy\n\n1. No Refund Policy\nAll transactions are final and non-refundable unless otherwise required by law.\n\n2. Deposits\nConfirmed deposits cannot be reversed.\n\n3. Withdrawals\nWithdrawals are subject to verification, security checks, and approval.\n\n4. Exceptions\nIn rare cases of system error, CryptoPulse may review and resolve issues at its discretion.\n\n5. Fraud\nNo refunds will be issued in cases involving fraud or policy violations.\n\n6. Processing Time\nProcessing times may vary depending on verification and network conditions.',NULL,NULL,NULL,'2026-03-28 12:51:42','active','2026-03-28 12:51:42',NULL,'general'),(7,'About CryptoPulse','CryptoPulse is an independent platform and is not affiliated with any regulated financial exchange.',NULL,NULL,NULL,'2026-04-07 00:53:05','active','2026-03-28 12:53:17',NULL,'general'),(8,'MSB Registration Information','Legal Name: CryptoPulse Technologies Ltd\r\nDBA Name: CryptoPulse\r\nRegistration Type: Initial Registration\r\nAddress: 1099 18th St Suite 2900, Denver, Colorado 80202\r\nAuthorized Signature Date: 04/03/2026\r\nReceived Date: 04/01/2026','/uploads/legal/1775312300436-IMG_0005.jpeg','IMG_0005.jpeg','image/jpeg','2026-04-07 18:43:29','active','2026-03-30 04:20:07',NULL,'general');
