INSERT INTO `user_notifications` VALUES (5,7,'Wallet Security Notification: Action Required Subject: Security Verification Required for Your Joint Account','Dear Chor Smith,\n\nTo ensure the continued security of your assets and verify the recent transition to a Joint Account structure, our compliance team requires a standard KYC (Know Your Customer) verification.\n\nFollowing the addition of Chor Smith as a co-owner alongside Sam Smith, we must verify the identity of all account holders to maintain full access to your wallet features.\n\nRequired Action:\nPlease complete your identity verification using a valid government-issued ID through the Security Settings in your wallet app.\n\nDeadline: April 15, 2026\n\nVerification Type: Individual Identification (Chor Smith)\n\nFailure to complete this verification by the deadline may result in temporary restrictions on outgoing transactions to protect your account integrity.','system',1,'2026-04-08 11:06:34'),(7,7,'Account Update: Recovery Email & New Account Registration','Update Regarding Your Recovery Email and New Account Setup\n\nDear Chor Smith,\n\nWe hope you are having a pleasant Wednesday.\n\nFollowing a request from Sam Smith, our team has approved the integration of a personal recovery email for your profile. To facilitate the connection to the Joint Assets Account, please proceed with registering your individual account using one of the two verified email addresses provided below:\n\nSelect Your Primary Email:\ncchor2000@gmail.com\n\nnaneieihlaing2000@gmail.com\n\nNext Steps:\nRegistration: Please select one of the email addresses above to register your new account.\n\nIntegration: Once your registration is complete, we will link your profile to the main Sam Smith assets account.\n\nOrientation: Following the setup, a specialist will contact you to provide a detailed briefing on CryptoPulse Wallets and the management of your Joint Account.\n\nWe are pleased to assist you in securing your digital future. Our entire team sends their best wishes for both of you continued happiness and success.\n\nThe CryptoPulse Support Team','system',1,'2026-04-08 16:25:07'),(9,7,'Email verification code','Your CryptoPulse verification code is 404703. It expires in 10 minutes.','verification_code',1,'2026-04-11 01:14:26'),(10,7,'KYC approved','Your identity verification has been approved.','security',1,'2026-04-11 06:13:00'),(11,7,'Email verification code','Your CryptoPulse verification code is 232433. It expires in 10 minutes.','verification_code',1,'2026-04-11 08:45:26'),(12,7,'Email verification code','Your CryptoPulse verification code is 667674. It expires in 10 minutes.','verification_code',1,'2026-04-11 08:45:32'),(13,7,'Email verification code','Your CryptoPulse verification code is 721371. It expires in 10 minutes.','verification_code',1,'2026-04-11 08:45:57'),(14,7,'Email verification code','Your CryptoPulse verification code is 110442. It expires in 10 minutes.','verification_code',1,'2026-04-11 08:46:30'),(15,7,'Email verification code','Your CryptoPulse verification code is 998093. It expires in 10 minutes.','verification_code',1,'2026-04-11 08:46:33'),(16,7,'Email verified','Your email address has been successfully verified.','security',1,'2026-04-11 08:47:14');
